/* ---------------- search engine (deterministic) ---------------- */
const norm = s => (s || "").toLowerCase();
function scoreRecord(rec, tokens) {
  const hay = norm(rec.name + " " + rec.sub + " " + rec.kw + " " + rec.stat + " " + rec.det);
  let score = 0;
  for (const t of tokens) if (t && hay.includes(t)) score += 1;
  return score;
}
function searchRecords(query, cat) {
  const tokens = norm(query).split(/\s+/).filter(Boolean);
  let pool = cat && cat !== "all" ? DATA.filter(r => r.cat === cat) : DATA;
  if (tokens.length === 0) return pool;
  return pool
    .map(r => ({ r, s: scoreRecord(r, tokens) }))
    .filter(x => x.s > 0)
    .sort((a, b) => b.s - a.s)
    .map(x => x.r);
}

/* ---------------- UI ---------------- */
const GOLD = "#c9a84c", RED = "#c0392b", BG = "#0a0807", PANEL = "#141008";

// who began each item — the credibility field
const ORIGIN = {
  started:   { label: "Started by DMK",      color: "#22c55e", mark: "✓" },
  expanded:  { label: "Expanded by DMK",     color: "#d97706", mark: "↗" },
  continued: { label: "Continued under DMK", color: "#8a8aa0", mark: "→" },
};
const SHARE_LINE = {
  started:   "Started and implemented by the DMK government — not the present one.",
  expanded:  "Significantly expanded and funded by the DMK government.",
  continued: "Continued and strengthened under the DMK government.",
};
const claimVerdict = o =>
  o === "expanded"  ? "✅ In the record — the DMK government significantly expanded this."
: o === "continued" ? "✅ In the record — this was continued and strengthened under the DMK government."
:                     "✅ In the record — this was started by the DMK government.";

function RisingSun({ size = 30 }) {
  return (
    <svg width={size} height={size} viewBox="0 0 60 60" aria-hidden>
      <circle cx="30" cy="38" r="11" fill={RED} />
      {Array.from({ length: 9 }).map((_, i) => {
        const a = (Math.PI * i) / 8;
        const x1 = 30 - Math.cos(a) * 16, y1 = 38 - Math.sin(a) * 16;
        const x2 = 30 - Math.cos(a) * 25, y2 = 38 - Math.sin(a) * 25;
        return <line key={i} x1={x1} y1={y1} x2={x2} y2={y2} stroke={RED} strokeWidth="2.4" strokeLinecap="round" />;
      })}
    </svg>
  );
}

function RecordCard({ rec, onCard }) {
  const c = CAT[rec.cat];
  return (
    <div style={{ background: PANEL, border: "1px solid #241c0c", borderLeft: `3px solid ${c.color}`, borderRadius: 10, padding: "16px 18px", marginBottom: 12 }}>
      <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 12 }}>
        <div style={{ flex: 1 }}>
          <div style={{ fontSize: 11, color: c.color, fontFamily: "monospace", letterSpacing: ".12em", textTransform: "uppercase", marginBottom: 6 }}>{c.emoji} {c.en} · {rec.date}</div>
          {rec.origin && ORIGIN[rec.origin] && (
            <div style={{ display: "inline-block", fontSize: 10.5, color: ORIGIN[rec.origin].color, border: `1px solid ${ORIGIN[rec.origin].color}55`, borderRadius: 5, padding: "2px 7px", marginBottom: 7, fontFamily: "monospace", letterSpacing: ".04em" }}>{ORIGIN[rec.origin].mark} {ORIGIN[rec.origin].label}</div>
          )}
          <div style={{ color: "#f3ecd9", fontSize: 16.5, fontWeight: 700, lineHeight: 1.35 }}>{rec.name}</div>
          {rec.sub && <div style={{ color: "#9c8e6e", fontSize: 13, marginTop: 2, fontStyle: "italic" }}>{rec.sub}</div>}
        </div>
        <div style={{ textAlign: "right", color: c.color, fontWeight: 800, fontSize: 16, whiteSpace: "nowrap", maxWidth: 160 }}>{rec.stat}</div>
      </div>
      <p style={{ color: "rgba(243,236,217,.74)", fontSize: 13.5, lineHeight: 1.7, margin: "12px 0 0" }}>{rec.det}</p>
      <button onClick={() => onCard(rec)} style={{ marginTop: 12, padding: "6px 13px", background: "transparent", border: `1px solid ${GOLD}55`, color: GOLD, borderRadius: 7, fontSize: 11.5, cursor: "pointer", fontFamily: "monospace", letterSpacing: ".08em" }}>
        → Make card
      </button>
    </div>
  );
}

function ShareCard({ rec, onClose }) {
  const c = CAT[rec.cat];
  const [copied, setCopied] = useState(false);
  const text =
`✅ DMK Government — Tamil Nadu, 2021–2026

${rec.name}${rec.sub ? " (" + rec.sub + ")" : ""}

📊 ${rec.stat}
📅 ${rec.date}
${rec.det}

➡️ ${SHARE_LINE[rec.origin] || SHARE_LINE.started}

📄 Source: Tamil Nadu Government record (2021–26)
#DMK #TamilNadu #VerifiedRecord`;
  const copy = () => { navigator.clipboard?.writeText(text); setCopied(true); setTimeout(() => setCopied(false), 1800); };
  return (
    <div style={{ position: "fixed", inset: 0, background: "rgba(0,0,0,.9)", display: "flex", alignItems: "center", justifyContent: "center", zIndex: 1000, padding: 18 }} onClick={onClose}>
      <div style={{ maxWidth: 460, width: "100%" }} onClick={e => e.stopPropagation()}>
        <div style={{ background: BG, border: `2px solid ${c.color}`, borderRadius: 14, overflow: "hidden" }}>
          <div style={{ background: c.color, padding: "11px 20px", display: "flex", justifyContent: "space-between", alignItems: "center" }}>
            <span style={{ color: "#fff", fontSize: 11.5, fontFamily: "monospace", letterSpacing: ".14em", textTransform: "uppercase" }}>DMK · 2021–2026</span>
            <RisingSun size={22} />
          </div>
          <div style={{ padding: "26px 22px" }}>
            <div style={{ fontSize: 10.5, color: c.color, fontFamily: "monospace", letterSpacing: ".2em", marginBottom: 12 }}>✅ VERIFIED RECORD</div>
            <h2 style={{ color: "#f3ecd9", fontSize: 22, fontWeight: 800, lineHeight: 1.3, margin: 0 }}>{rec.name}</h2>
            {rec.sub && <div style={{ color: "#9c8e6e", fontSize: 13.5, marginTop: 4, fontStyle: "italic" }}>{rec.sub}</div>}
            <div style={{ background: `${c.color}1c`, border: `1px solid ${c.color}44`, borderRadius: 10, padding: "16px 18px", margin: "18px 0 14px" }}>
              <div style={{ color: c.color, fontSize: 25, fontWeight: 800, lineHeight: 1.1 }}>{rec.stat}</div>
            </div>
            <p style={{ color: "rgba(243,236,217,.8)", fontSize: 14, lineHeight: 1.7, margin: 0 }}>{rec.det}</p>
            <div style={{ marginTop: 14, paddingTop: 12, borderTop: "1px solid #241c0c", color: "rgba(243,236,217,.45)", fontSize: 12 }}>📅 {rec.date} · 📄 Tamil Nadu Government record</div>
          </div>
        </div>
        <div style={{ display: "flex", gap: 10, marginTop: 14 }}>
          <button onClick={copy} style={{ flex: 1, padding: 13, background: copied ? "#16a34a" : c.color, color: "#fff", border: "none", borderRadius: 9, fontSize: 14, fontWeight: 700, cursor: "pointer" }}>
            {copied ? "✓ Copied" : "📋 Copy for WhatsApp / Social"}
          </button>
          <button onClick={onClose} style={{ padding: "13px 18px", background: "#1c1710", color: "#9c8e6e", border: "1px solid #2a2114", borderRadius: 9, fontSize: 14, cursor: "pointer" }}>Close</button>
        </div>
      </div>
    </div>
  );
}

/* ---------------- manifesto tracker ---------------- */
const PSTATUS = {
  kept:         { label: "Kept",             color: "#22c55e", mark: "✓" },
  progress:     { label: "In progress",      color: "#c9a84c", mark: "◐" },
  unverified:   { label: "Not yet verified", color: "#8a8aa0", mark: "·" },
  "not-done":   { label: "Not done",         color: "#c0392b", mark: "✕" },
};
const RECBYID = Object.fromEntries(DATA.map(r => [r.id, r]));

function ManifestoTracker({ query, mStatus, setMStatus, onPickRecord }) {
  const tokens = norm(query).split(/\s+/).filter(Boolean);
  const counts = { kept: 0, progress: 0, unverified: 0, "not-done": 0 };
  PROMISES.forEach(p => { counts[p.status] = (counts[p.status] || 0) + 1; });
  const total = PROMISES.length;
  const done = counts.kept + counts.progress;

  const match = p => {
    if (mStatus !== "all" && p.status !== mStatus) return false;
    if (tokens.length === 0) return true;
    const hay = norm(p.text + " " + p.num + " " + p.theme);
    return tokens.every(t => hay.includes(t));
  };
  const list = PROMISES.filter(match);

  // group by theme, preserving first-seen order
  const order = [], byTheme = {};
  list.forEach(p => { if (!byTheme[p.theme]) { byTheme[p.theme] = []; order.push(p.theme); } byTheme[p.theme].push(p); });

  const FILTERS = [
    { id: "all", label: `All ${total}`, color: GOLD },
    { id: "kept", label: `Kept ${counts.kept}`, color: PSTATUS.kept.color },
    { id: "progress", label: `In progress ${counts.progress}`, color: PSTATUS.progress.color },
    { id: "unverified", label: `Not yet verified ${counts.unverified}`, color: PSTATUS.unverified.color },
  ];
  if (counts["not-done"]) FILTERS.push({ id: "not-done", label: `Not done ${counts["not-done"]}`, color: PSTATUS["not-done"].color });

  return (
    <div style={{ marginTop: 4 }}>
      {/* SUMMARY */}
      <div style={{ background: PANEL, border: "1px solid #241c0c", borderRadius: 12, padding: "16px 18px", marginBottom: 14 }}>
        <div style={{ display: "flex", gap: 10, marginBottom: 12 }}>
          {[["kept", counts.kept], ["progress", counts.progress], ["unverified", counts.unverified]].map(([k, n]) => (
            <div key={k} style={{ flex: 1, textAlign: "center", background: `${PSTATUS[k].color}14`, border: `1px solid ${PSTATUS[k].color}44`, borderRadius: 9, padding: "10px 6px" }}>
              <div style={{ color: PSTATUS[k].color, fontSize: 22, fontWeight: 800, lineHeight: 1 }}>{n}</div>
              <div style={{ color: PSTATUS[k].color, fontSize: 10.5, fontFamily: "monospace", letterSpacing: ".06em", marginTop: 5 }}>{PSTATUS[k].label}</div>
            </div>
          ))}
        </div>
        <p style={{ color: "#7a6c4c", fontSize: 11.5, lineHeight: 1.7, margin: 0 }}>
          All {total} promises from the 2021 DMK manifesto. <b style={{ color: PSTATUS.kept.color }}>Kept</b> and <b style={{ color: PSTATUS.progress.color }}>in-progress</b> promises are each linked to a verified record below. <b style={{ color: PSTATUS.unverified.color }}>Not yet verified</b> means the achievement record isn't in this tool yet — many are central-government matters or await later document batches — <i>not</i> that the promise was broken. Tap a linked scheme to open its shareable card.
        </p>
      </div>

      {/* STATUS FILTER */}
      <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 14 }}>
        {FILTERS.map(f => (
          <button key={f.id} onClick={() => setMStatus(f.id)} style={{ padding: "5px 11px", fontSize: 11.5, background: mStatus === f.id ? f.color + "22" : PANEL, border: `1px solid ${mStatus === f.id ? f.color + "88" : "#241c0c"}`, color: mStatus === f.id ? f.color : "#6e6244", borderRadius: 20, cursor: "pointer" }}>{f.label}</button>
        ))}
      </div>

      {/* RESULTS */}
      <div style={{ color: "#3f381f", fontSize: 10, fontFamily: "monospace", letterSpacing: ".15em", marginBottom: 10 }}>{list.length} promise{list.length === 1 ? "" : "s"}{query ? ` · "${query}"` : ""}</div>
      {order.length === 0 && <div style={{ background: PANEL, border: "1px solid #241c0c", borderRadius: 12, padding: 18, color: "#9c8e6e", fontSize: 14 }}>No promise matches — try other words or a promise number.</div>}
      {order.map(theme => (
        <div key={theme} style={{ marginBottom: 18 }}>
          <div style={{ color: GOLD, fontSize: 11.5, fontFamily: "monospace", letterSpacing: ".1em", textTransform: "uppercase", marginBottom: 8, paddingBottom: 5, borderBottom: "1px solid #241c0c" }}>{theme} · {byTheme[theme].length}</div>
          {byTheme[theme].map(p => {
            const st = PSTATUS[p.status];
            return (
              <div key={p.num} style={{ background: PANEL, border: "1px solid #1c1710", borderLeft: `3px solid ${st.color}`, borderRadius: 9, padding: "11px 13px", marginBottom: 8 }}>
                <div style={{ display: "flex", justifyContent: "space-between", alignItems: "flex-start", gap: 10 }}>
                  <div style={{ flex: 1 }}>
                    <span style={{ color: "#5b5036", fontSize: 12, fontFamily: "monospace" }}>#{p.num}</span>
                    <span style={{ color: "#e9e0c8", fontSize: 13.5, lineHeight: 1.5, marginLeft: 7 }}>{p.text}</span>
                  </div>
                  <div style={{ color: st.color, fontSize: 10, fontFamily: "monospace", border: `1px solid ${st.color}55`, borderRadius: 5, padding: "2px 6px", whiteSpace: "nowrap" }}>{st.mark} {st.label}</div>
                </div>
                {p.records.length > 0 && (
                  <div style={{ display: "flex", flexWrap: "wrap", gap: 5, marginTop: 9 }}>
                    {p.records.map(id => RECBYID[id] && (
                      <button key={id} onClick={() => onPickRecord(id)} style={{ fontSize: 11, padding: "3px 9px", background: "transparent", border: `1px solid ${(CAT[RECBYID[id].cat] || {}).color || GOLD}55`, color: (CAT[RECBYID[id].cat] || {}).color || GOLD, borderRadius: 14, cursor: "pointer" }}>{RECBYID[id].name} →</button>
                    ))}
                  </div>
                )}
              </div>
            );
          })}
        </div>
      ))}
    </div>
  );
}

const MODES = [
  { id: "search",    label: "Search",        icon: "🔍", desc: "Find what DMK did on any topic" },
  { id: "claim",     label: "Check a claim", icon: "⚡", desc: "Did DMK start it, or someone else?" },
  { id: "manifesto", label: "Manifesto",     icon: "📜", desc: "2021 promises, tracked honestly" },
];

export default function DMKChecker() {
  const [mode, setMode] = useState("search");
  const [query, setQuery] = useState("");
  const [cat, setCat] = useState("all");
  const [card, setCard] = useState(null);
  const [submitted, setSubmitted] = useState(false);
  const [mStatus, setMStatus] = useState("all");

  const results = useMemo(() => searchRecords(query, cat), [query, cat]);

  const QUICK = ["free bus", "Magalir Urimai", "breakfast", "Naan Mudhalvan", "Keeladi", "metro rail", "desalination", "cybercrime", "GSDP growth", "stormwater drain", "doorstep medicine", "street vendor loan"];
  const CLAIMS = ["New govt started free bus for women", "New govt started free breakfast", "₹1000 is given by the new government", "New govt built the Keeladi museum", "New govt opened Kalaignar hospital"];

  const claimTop = mode === "claim" && submitted ? results[0] : null;

  return (
    <div style={{ minHeight: "100vh", background: BG, color: "#f3ecd9", fontFamily: "'Inter',system-ui,sans-serif" }}>
      <style>{`
        @import url('https://fonts.googleapis.com/css2?family=Inter:wght@400;500;700;800&display=swap');
        *{box-sizing:border-box} body{margin:0}
        ::-webkit-scrollbar{width:6px}::-webkit-scrollbar-thumb{background:#2a2114;border-radius:3px}
        :focus-visible{outline:2px solid ${GOLD};outline-offset:2px}
        ::placeholder{color:#5b5036}
      `}</style>

      {/* HEADER */}
      <div style={{ borderBottom: "1px solid #1c1710", background: "#0d0a05", position: "sticky", top: 0, zIndex: 100 }}>
        <div style={{ maxWidth: 720, margin: "0 auto", padding: "16px 18px", display: "flex", alignItems: "center", gap: 12 }}>
          <RisingSun size={34} />
          <div style={{ flex: 1 }}>
            <h1 style={{ margin: 0, fontSize: 19, fontWeight: 800, color: "#f3ecd9" }}>DMK Record Checker</h1>
            <p style={{ margin: 0, fontSize: 10.5, color: "#7a6c4c", fontFamily: "monospace", letterSpacing: ".1em" }}>TAMIL NADU · 2021–2026 · WHO STARTED IT?</p>
          </div>
          <div style={{ fontSize: 10, color: RED, border: `1px solid ${RED}55`, borderRadius: 6, padding: "5px 9px", fontFamily: "monospace", textAlign: "center", lineHeight: 1.4 }}>OFFLINE<br />VERIFIED</div>
        </div>
      </div>

      <div style={{ maxWidth: 720, margin: "0 auto", padding: "20px 18px 60px" }}>
        {/* MODE */}
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr 1fr", gap: 8, marginBottom: 18 }}>
          {MODES.map(m => (
            <button key={m.id} onClick={() => { setMode(m.id); setSubmitted(false); }} style={{ padding: "13px 14px", background: mode === m.id ? "rgba(201,168,76,.1)" : PANEL, border: mode === m.id ? `1px solid ${GOLD}77` : "1px solid #1c1710", borderRadius: 11, cursor: "pointer", textAlign: "left" }}>
              <div style={{ fontSize: 19, marginBottom: 3 }}>{m.icon}</div>
              <div style={{ color: mode === m.id ? GOLD : "#9c8e6e", fontSize: 13.5, fontWeight: 700 }}>{m.label}</div>
              <div style={{ color: "#5b5036", fontSize: 11.5, marginTop: 2 }}>{m.desc}</div>
            </button>
          ))}
        </div>

        {/* CATEGORY (search only) */}
        {mode === "search" && (
          <div style={{ display: "flex", gap: 6, flexWrap: "wrap", marginBottom: 14 }}>
            {CATEGORIES.map(c => (
              <button key={c.id} onClick={() => setCat(c.id)} style={{ padding: "4px 11px", fontSize: 11.5, background: cat === c.id ? c.color + "22" : PANEL, border: `1px solid ${cat === c.id ? c.color + "66" : "#241c0c"}`, color: cat === c.id ? c.color : "#6e6244", borderRadius: 20, cursor: "pointer" }}>{c.emoji} {c.en}</button>
            ))}
          </div>
        )}

        {/* INPUT */}
        <div style={{ position: "relative", marginBottom: 14 }}>
          <input
            value={query}
            onChange={e => { setQuery(e.target.value); setSubmitted(mode === "search"); }}
            onKeyDown={e => { if (e.key === "Enter") setSubmitted(true); }}
            placeholder={mode === "search" ? "Search a scheme, number or topic…" : mode === "claim" ? "Type a claim… e.g. 'new govt started free bus'" : "Filter promises — a word or a number…"}
            style={{ width: "100%", padding: "15px 52px 15px 16px", background: PANEL, border: "1px solid #241c0c", borderRadius: 12, color: "#f3ecd9", fontSize: 15 }}
          />
          <button onClick={() => setSubmitted(true)} style={{ position: "absolute", right: 10, top: 9, width: 36, height: 36, borderRadius: 8, background: query.trim() ? RED : "#1c1710", border: "none", color: "#fff", fontSize: 16, cursor: query.trim() ? "pointer" : "default" }}>→</button>
        </div>

        {/* QUICK CHIPS */}
        {!submitted && mode !== "manifesto" && (
          <div style={{ marginBottom: 8 }}>
            <div style={{ color: "#3f381f", fontSize: 10, fontFamily: "monospace", letterSpacing: ".15em", marginBottom: 7 }}>{mode === "search" ? "QUICK SEARCH" : "EXAMPLE CLAIMS"}</div>
            <div style={{ display: "flex", flexWrap: "wrap", gap: 6 }}>
              {(mode === "search" ? QUICK : CLAIMS).map(q => (
                <button key={q} onClick={() => { setQuery(q); setSubmitted(true); }} style={{ padding: "5px 11px", fontSize: 12, background: PANEL, border: `1px solid ${mode === "claim" ? RED + "33" : "#241c0c"}`, color: "#7a6c4c", borderRadius: 20, cursor: "pointer" }}>{mode === "claim" ? "⚡ " : ""}{q}</button>
              ))}
            </div>
          </div>
        )}

        {/* CLAIM VERDICT */}
        {mode === "claim" && submitted && (
          <div style={{ marginTop: 16 }}>
            {claimTop ? (
              <>
                <div style={{ background: "rgba(22,163,74,.08)", border: "1px solid rgba(22,163,74,.4)", borderRadius: 12, padding: "16px 18px", marginBottom: 14 }}>
                  <div style={{ color: "#22c55e", fontSize: 13, fontWeight: 800, marginBottom: 6 }}>{claimVerdict(claimTop.origin)}</div>
                  <div style={{ color: "rgba(243,236,217,.85)", fontSize: 14, lineHeight: 1.7 }}>
                    <b>{claimTop.name}</b> — {(SHARE_LINE[claimTop.origin] || SHARE_LINE.started).replace(/\.$/, "")} ({claimTop.date}). The verified record contradicts any claim that another government is responsible.
                  </div>
                </div>
                <RecordCard rec={claimTop} onCard={setCard} />
                {results.length > 1 && <div style={{ color: "#5b5036", fontSize: 11, fontFamily: "monospace", margin: "4px 0 10px" }}>Related records:</div>}
                {results.slice(1, 4).map(r => <RecordCard key={r.id} rec={r} onCard={setCard} />)}
              </>
            ) : (
              <div style={{ background: PANEL, border: "1px solid #241c0c", borderRadius: 12, padding: "18px", color: "#9c8e6e", fontSize: 14, lineHeight: 1.7 }}>
                No matching record found — try different keywords.
              </div>
            )}
          </div>
        )}

        {/* MANIFESTO TRACKER */}
        {mode === "manifesto" && (
          <ManifestoTracker query={query} mStatus={mStatus} setMStatus={setMStatus} onPickRecord={id => { const r = RECBYID[id]; if (r) setCard(r); }} />
        )}

        {/* SEARCH RESULTS */}
        {mode === "search" && (
          <div style={{ marginTop: 16 }}>
            <div style={{ color: "#3f381f", fontSize: 10, fontFamily: "monospace", letterSpacing: ".15em", marginBottom: 10 }}>{results.length} record{results.length === 1 ? "" : "s"}{query ? ` · "${query}"` : (cat !== "all" ? ` · ${CAT[cat].en}` : "")}</div>
            {(!query && cat === "all")
              ? <div style={{ background: PANEL, border: "1px solid #241c0c", borderRadius: 12, padding: "20px", color: "#9c8e6e", fontSize: 14, lineHeight: 1.7 }}>
                  Pick a category above, tap a quick search, or type a topic, number or scheme name. <b style={{ color: GOLD }}>{DATA.length}</b> verified records are loaded — all from the Tamil Nadu Government 2021–26 record.
                </div>
              : results.length ? results.map(r => <RecordCard key={r.id} rec={r} onCard={setCard} />)
              : <div style={{ background: PANEL, border: "1px solid #241c0c", borderRadius: 12, padding: 18, color: "#9c8e6e", fontSize: 14 }}>No match — try other words.</div>}
          </div>
        )}

        {/* FOOTER */}
        <div style={{ marginTop: 36, padding: "13px 16px", background: "#0d0a05", border: "1px solid #1c1710", borderRadius: 9 }}>
          <p style={{ color: "#3f381f", fontSize: 10.5, fontFamily: "monospace", margin: 0, lineHeight: 1.7 }}>
            Source: Tamil Nadu Government 2021–26 achievement record (souvenir, minister-by-minister). Every fact comes only from that document — no AI, no internet. Runs fully offline. Where the document itself gives differing figures for one item, the record notes both.
          </p>
        </div>
      </div>

      {card && <ShareCard rec={card} onClose={() => setCard(null)} />}
    </div>
  );
}
